class BackendService {
  // Replace with your actual secure backend URL
  static const String kBackendUrl = 'https://your-secure-backend.com'; // IMPORTANT: Use HTTPS for production!

  // This method would call your backend to create a Stripe PaymentIntent.
  // Your backend will communicate with the Stripe API using your secret key.
  Future<Map<String, dynamic>> createStripePaymentIntent(double amount, String currency, String? paymentMethodId) async {
    print('Calling backend to create PaymentIntent for $amount $currency');
    try {
      final response = await http.post(
        Uri.parse('$kBackendUrl/create-payment-intent'), // Your backend endpoint
        headers: {'Content-Type': 'application/json'},
        body: json.encode({
          'amount': (amount * 100).toInt(), // Stripe expects amount in cents
          'currency': currency,
          'paymentMethodId': paymentMethodId, // Optional, for initial card payments
        }),
      );

      if (response.statusCode == 200) {
        final Map<String, dynamic> responseData = json.decode(response.body);
        if (responseData.containsKey('client_secret') && responseData.containsKey('id')) {
          print('PaymentIntent created by backend: ${responseData['id']}');
          return responseData; // Should contain 'client_secret' and 'id'
        } else {
          throw Exception('Backend response missing client_secret or id: $responseData');
        }
      } else {
        throw Exception('Failed to create payment intent on backend: ${response.statusCode} - ${response.body}');
      }
    } catch (e) {
      print('Error creating PaymentIntent via backend: $e');
      rethrow;
    }
  }

  // This method would call your backend to verify an In-App Purchase receipt.
  // Your backend should send the receipt data to Apple/Google's verification servers.
  Future<bool> verifyIAPReceipt(String receiptData, String productId) async {
    print('Calling backend to verify IAP receipt for $productId');
    try {
      final response = await http.post(
        Uri.parse('$kBackendUrl/verify-iap-receipt'), // Your backend endpoint
        headers: {'Content-Type': 'application/json'},
        body: json.encode({
          'receiptData': receiptData,
          'productId': productId,
          'platform': Platform.isIOS ? 'ios' : 'android',
        }),
      );

      if (response.statusCode == 200) {
        final Map<String, dynamic> responseData = json.decode(response.body);
        final bool isVerified = responseData['verified'] == true;
        if (isVerified) {
          print('IAP receipt verified by backend for $productId');
        } else {
          print('IAP receipt NOT verified by backend for $productId: ${responseData['message']}');
        }
        return isVerified;
      } else {
        throw Exception('Failed to verify IAP receipt on backend: ${response.statusCode} - ${response.body}');
      }
    } catch (e) {
      print('Error verifying IAP receipt via backend: $e');
      rethrow;
    }
  }
}

