  // --- Stripe Payment Methods (Apple Pay / Google Pay) ---

  Future<PaymentIntent> _processWalletPayment(double amount, String currency, bool isApplePay) async {
    try {
      // 1. Check if wallet payment is supported
      if (isApplePay && !await Stripe.instance.isApplePaySupported()) {
        throw Exception('Apple Pay is not supported on this device.');
