      final String clientSecret = paymentIntentData['client_secret'];
      final String paymentIntentId = paymentIntentData['id'];

      // 3. Present the payment sheet (Apple Pay or Google Pay).
      // Stripe's `presentPaymentSheet` handles the entire flow including confirming the PaymentIntent
