        '4242424242424242', // Stripe test card number (use real ones for production)
        '12', // Exp month (e.g., 12)
        '2025', // Exp year (e.g., 2025)
        '123', // CVC (e.g., 123)
        10.00, // Amount
        'usd', // Currency
