    try {
      final PaymentIntent intent = await widget.paymentService.initiateApplePay(30.00, 'usd');
      _updateStatus('Apple Pay Succeeded: ${intent.id}');
    } catch (e) {
      _updateStatus('Apple Pay Failed: ${e.toString()}');
    }
  }

  Future<void> _purchaseIAPProduct(String productId) async {
    _updateStatus('Initiating IAP for $productId...');
    try {
      final purchaseDetails = await widget.paymentService.purchaseProduct(productId);
      _updateStatus('IAP Succeeded: ${purchaseDetails.productID}');
    } catch (e) {
      _updateStatus('IAP Failed for $productId: ${e.toString()}');
